from anthropic import Anthropic
from retrieval import hybrid_search
from evals import log_trace

client = Anthropic()

def answer(question: str, user_id: str) -> str:
    docs = hybrid_search(question, top_k=8, rerank=True)

    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        system=[{
            "type": "text",
            "text": SYSTEM_PROMPT,
            "cache_control": {"type": "ephemeral"}
        }],
        messages=[{
            "role": "user",
            "content": f"<docs>{docs}</docs>\n\n{question}"
        }],
        tools=TOOLS,
    )

    log_trace(user_id, question, response)
    return response.content[0].text
